import * as React from "react";
import { useForm } from "react-hook-form"
import type { JobTitle } from '@/lib/types/prisma-extended'
import { useJobTitleStore } from "./store";

import { Button } from "../../../components/ui/button"
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "../../../components/ui/form"
import { Input } from "../../../components/ui/input"
import { Textarea } from "../../../components/ui/textarea";

export type JobTitleFormValues = Omit<JobTitle, 'systemId'>;

type JobTitleFormProps = {
  initialData: JobTitle | null
  onSubmit: (values: JobTitleFormValues) => void;
  onCancel: () => void;
}

export function JobTitleForm({ initialData, onSubmit, onCancel }: JobTitleFormProps) {
  const { data: _jobTitles } = useJobTitleStore();
  const form = useForm<JobTitleFormValues>({
    defaultValues: initialData || {
      id: "", // ✅ Empty string = auto-generate
      name: "",
      description: "",
    },
  })

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
         <FormField
          control={form.control}
          name="id"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Mã chức vụ</FormLabel>
              <FormControl>
                <Input placeholder="VD: NV, TP" {...field} value={field.value ?? ''} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="name"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Tên chức vụ</FormLabel>
              <FormControl>
                <Input placeholder="VD: Trưởng phòng" {...field} value={field.value ?? ''} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="description"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Mô tả</FormLabel>
              <FormControl>
                <Textarea placeholder="Mô tả vai trò, trách nhiệm của chức vụ..." {...field} value={field.value ?? ''} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <div className="flex justify-end space-x-2 pt-4">
            <Button type="button" variant="outline" onClick={onCancel}>Hủy</Button>
            <Button type="submit">Lưu</Button>
        </div>
      </form>
    </Form>
  )
}
